(function(){const menuToggle=document.getElementById("menu-toggle");const navMenu=document.getElementById("nav-menu");if(menuToggle&&navMenu){menuToggle.addEventListener("click",function(){const isExpanded=menuToggle.getAttribute("aria-expanded")==="true";menuToggle.setAttribute("aria-expanded",!isExpanded);navMenu.classList.toggle("is-active");menuToggle.classList.toggle("is-active")})}})();